.darma-loader-darma-custom-654__container {color: var(--loader-color, #38bdf8);

  width: 140px;
  height: 140px;
  padding: 15px;
  display: flex;
  align-items: center;
  justify-content: center;
}

.darma-loader-darma-custom-654__cloud {
  width: 140px;
}

.darma-loader-darma-custom-654__front {
  padding-top: 45px;
  margin-left: 25px;
  display: inline;
  position: absolute;
  z-index: 11;
  animation: darma-loader-darma-custom-654-clouds 8s infinite;
  animation-timing-function: ease-in-out;
}

.darma-loader-darma-custom-654__back {
  margin-top: -30px;
  margin-left: 150px;
  z-index: 12;
  animation: darma-loader-darma-custom-654-clouds 12s infinite;
  animation-timing-function: ease-in-out;
}

.darma-loader-darma-custom-654__right-front {
  width: 45px;
  height: 45px;
  border-radius: 50% 50% 50% 0%;
  background-color: #4c9beb;
  display: inline-block;
  margin-left: -25px;
  z-index: 5;
}

.darma-loader-darma-custom-654__left-front {
  width: 65px;
  height: 65px;
  border-radius: 50% 50% 0% 50%;
  background-color: #4c9beb;
  display: inline-block;
  z-index: 5;
}

.darma-loader-darma-custom-654__right-back {
  width: 50px;
  height: 50px;
  border-radius: 50% 50% 50% 0%;
  background-color: #4c9beb;
  display: inline-block;
  margin-left: -20px;
  z-index: 5;
}

.darma-loader-darma-custom-654__left-back {
  width: 30px;
  height: 30px;
  border-radius: 50% 50% 0% 50%;
  background-color: #4c9beb;
  display: inline-block;
  z-index: 5;
}

.darma-loader-darma-custom-654__sun {
  width: 72px;
  height: 72px;
  background: -webkit-linear-gradient(to right, #fcbb04, #fffc00);
  background: linear-gradient(to right, #fcbb04, #fffc00);
  border-radius: 60px;
  display: inline;
  position: absolute;
}

.darma-loader-darma-custom-654__sunshine {
  animation: darma-loader-darma-custom-654-sunshines 2s infinite;
}

@keyframes darma-loader-darma-custom-654-sunshines {
  0% {
    transform: scale(1);
    opacity: 0.6;
  }

  100% {
    transform: scale(1.4);
    opacity: 0;
  }
}

@keyframes darma-loader-darma-custom-654-clouds {
  0% {
    transform: translateX(15px);
  }

  50% {
    transform: translateX(0px);
  }

  100% {
    transform: translateX(15px);
  }
}

